@mixin grid-column-position($position) {
  // Auto positioning
  @if $position == auto {
    &, &:last-child:not(:first-child) {
      float: $global-left;
      clear: none;
    }

    // Last column alignment
    @if $grid-column-align-edge {
      &:last-child:not(:first-child) {
        float: $global-right;
      }
    }
  }

  // Push/pull
  @else if type-of($position) == 'number' {
    $offset: percentage(divide($position, $grid-column-count));

    position: relative;
    #{$global-left}: $offset;
  }

  // Center positioning
  @else if $position == center {
    margin-left: auto;
    margin-right: auto;
    &, &:last-child:not(:first-child) {
      float: none;
      clear: both;
    }
  }

  @else {
    @warn 'Wrong syntax for grid-column-position(). Enter a positive or negative number, "center" or "auto".';
  }
}

@use "sass:color";
@use "sass:math";

@function color-translucent($target-color, $alpha: .1, $bg-color: #fff) {
  @if color.alpha($target-color) < 1 {
    @return $target-color;
  }

  @if $alpha <= 0 or $alpha > 1 {
    @error "Alpha must be greater than 0 and less than or equal to 1.";
  }

  $r: math.div(
    color.channel($target-color, "red") - color.channel($bg-color, "red") * (1 - $alpha),
    $alpha
  );

  $g: math.div(
    color.channel($target-color, "green") - color.channel($bg-color, "green") * (1 - $alpha),
    $alpha
  );

  $b: math.div(
    color.channel($target-color, "blue") - color.channel($bg-color, "blue") * (1 - $alpha),
    $alpha
  );

  @if $r < 0 or $r > 255 or $g < 0 or $g > 255 or $b < 0 or $b > 255 {
    @error "Cannot reproduce #{$target-color} on #{$bg-color} with alpha #{$alpha}. Try a higher alpha.";
  }

  @return rgba(round($r), round($g), round($b), $alpha);
}

@use "../../settings" as *;
@use "./icon" as *;
@use "../../functions" as *;
@use "./screen-reader" as *;

$external-link-size: 1.75ex;

$icon-object: (
  "name": "launch",
  "color": currentColor,
  "height": $external-link-size,
  "svg-height": 24,
  "svg-width": 24,
  "position-x": center,
  "position-y": center,
);

@mixin external-link($contrast-bg: "default") {
  display: inline;

  // Screen reader label
  &::before {
    @include sr-only;
    content: $theme-external-link-sr-label-tab-same;
  }

  &[target="_blank"]::before {
    @include sr-only;
    content: $theme-external-link-sr-label-tab-new;
  }

  &::after {
    @include add-color-icon($icon-object, $contrast-bg);
    content: "";
    display: inline;
    margin-top: 0.7ex;
    margin-left: 2px;
    padding-left: 1.75ex;
    vertical-align: middle;
  }
}

// Progress
// Credit: https://css-tricks.com/html5-progress-element/
.progress {
  appearance: none;
  background: $bg-color-dark;
  border: 0;
  border-radius: $border-radius;
  color: $primary-color;
  height: $unit-1;
  position: relative;
  width: 100%;

  &::-webkit-progress-bar {
    background: transparent;
    border-radius: $border-radius;
  }

  &::-webkit-progress-value {
    background: $primary-color;
    border-radius: $border-radius;
  }

  &::-moz-progress-bar {
    background: $primary-color;
    border-radius: $border-radius;
  }

  &:indeterminate {
    animation: progress-indeterminate 1.5s linear infinite;
    background: $bg-color-dark linear-gradient(to right, $primary-color 30%, $bg-color-dark 30%) top left / 150% 150% no-repeat;

    &::-moz-progress-bar {
      background: transparent;
    }
  }
}

@keyframes progress-indeterminate {
  0% {
    background-position: 200% 0;
  }
  100% {
    background-position: -200% 0;
  }
}

// Tables
.table {
  border-collapse: collapse;
  border-spacing: 0;
  width: 100%;
  @if $rtl == true {
    text-align: right;
  } @else {
    text-align: left;
  }

  &.table-striped {
    tbody {
      tr:nth-of-type(odd) {
        background: $bg-color;
      }
    }
  }

  &,
  &.table-striped {
    tbody {
      tr {
        &.active {
          background: $bg-color-dark;
        }
      }
    }
  }

  &.table-hover {
    tbody {
      tr {
        &:hover {
          background: $bg-color-dark;
        }
      }
    }
  }

  // Scollable tables
  &.table-scroll {
    display: block;
    overflow-x: auto;
    padding-bottom: .75rem;
    white-space: nowrap;
  }

  td,
  th {
    border-bottom: $border-width solid $border-color;
    padding: $unit-3 $unit-2;
  }
  th {
    border-bottom-width: $border-width-lg;
  }
}

@use "variables" as *;

.placeholder {
  display: inline-block;
  min-height: 1em;
  vertical-align: middle;
  cursor: wait;
  background-color: currentcolor;
  opacity: $placeholder-opacity-max;

  &.btn::before {
    display: inline-block;
    content: "";
  }
}

// Sizing
.placeholder-xs {
  min-height: .6em;
}

.placeholder-sm {
  min-height: .8em;
}

.placeholder-lg {
  min-height: 1.2em;
}

// Animation
.placeholder-glow {
  .placeholder {
    animation: placeholder-glow 2s ease-in-out infinite;
  }
}

@keyframes placeholder-glow {
  50% {
    opacity: $placeholder-opacity-min;
  }
}

.placeholder-wave {
  mask-image: linear-gradient(130deg, $black 55%, rgba(0, 0, 0, (1 - $placeholder-opacity-min)) 75%, $black 95%);
  mask-size: 200% 100%;
  animation: placeholder-wave 2s linear infinite;
}

@keyframes placeholder-wave {
  100% {
    mask-position: -200% 0%;
  }
}

// Needs refactoring
// stylelint-disable selector-max-type
.markdown-body {
  // Tables
  table {
    display: block;
    width: 100%; // keep for backwards compatibility
    width: max-content;
    max-width: 100%;
    overflow: auto;
    font-variant: tabular-nums;

    th {
      // stylelint-disable-next-line primer/typography
      font-weight: $font-weight-bold;
    }

    th,
    td {
      // stylelint-disable-next-line primer/spacing
      padding: 6px 13px;
      // stylelint-disable-next-line primer/borders, primer/colors
      border: $border-width $border-style var(--borderColor-default, var(--color-border-default));
    }

    td {
      > :last-child {
        margin-bottom: 0;
      }
    }

    tr {
      background-color: var(--bgColor-default, var(--color-canvas-default));
      // stylelint-disable-next-line primer/borders, primer/colors
      border-top: $border-width $border-style var(--borderColor-muted, var(--color-border-muted));

      &:nth-child(2n) {
        background-color: var(--bgColor-muted, var(--color-canvas-subtle));
      }
    }

    img {
      background-color: transparent;
    }
  }
}

//
// Thumbnails
// --------------------------------------------------


// Mixin and adjust the regular image class
.thumbnail {
  display: block;
  padding: $thumbnail-padding;
  margin-bottom: $line-height-computed;
  line-height: $line-height-base;
  background-color: $thumbnail-bg;
  border: 1px solid $thumbnail-border;
  border-radius: $thumbnail-border-radius;
  @include transition(border .2s ease-in-out);

  > img,
  a > img {
    @include img-responsive;
    margin-right: auto;
    margin-left: auto;
  }

  // [converter] extracted a&:hover, a&:focus, a&.active to a.thumbnail:hover, a.thumbnail:focus, a.thumbnail.active

  // Image captions
  .caption {
    padding: $thumbnail-caption-padding;
    color: $thumbnail-caption-color;
  }
}

// Add a hover state for linked versions only
a.thumbnail:hover,
a.thumbnail:focus,
a.thumbnail.active {
  border-color: $link-color;
}

@use "contrast-ratio" as *;

// We use this function only in variables.scss because recursive imports are not allowed in Sass anymore.

@function color-contrast-variables($background, $color-contrast-dark, $color-contrast-light, $white, $black, $min-contrast-ratio) {
  $foregrounds: $color-contrast-light, $color-contrast-dark, $white, $black;
  $max-ratio: 0;
  $max-ratio-color: null;

  @each $color in $foregrounds {
    $contrast-ratio: contrast-ratio($background, $color);
    @if $contrast-ratio >= $min-contrast-ratio {
      @return $color;
    } @else if $contrast-ratio > $max-ratio {
      $max-ratio: $contrast-ratio;
      $max-ratio-color: $color;
    }
  }

  @warn "Found no color leading to #{$min-contrast-ratio}:1 contrast ratio against #{$background}...";

  @return $max-ratio-color;
}

@use "../utilities/css-variables" as cv;
@use "../utilities/initial-variables" as iv;
@use "../utilities/mixins" as mx;

$section-padding: 3rem 1.5rem !default;
$section-padding-desktop: 3rem 3rem !default;
$section-padding-medium: 9rem 4.5rem !default;
$section-padding-large: 18rem 6rem !default;

.#{iv.$class-prefix}section {
  @include cv.register-vars(
    (
      "section-padding": #{$section-padding},
      "section-padding-desktop": #{$section-padding-desktop},
      "section-padding-medium": #{$section-padding-medium},
      "section-padding-large": #{$section-padding-large},
    )
  );
  padding: cv.getVar("section-padding");

  // Responsiveness
  @include mx.desktop {
    padding: cv.getVar("section-padding-desktop");

    // Sizes
    &.#{iv.$class-prefix}is-medium {
      padding: cv.getVar("section-padding-medium");
    }

    &.#{iv.$class-prefix}is-large {
      padding: cv.getVar("section-padding-large");
    }
  }

  &.#{iv.$class-prefix}is-fullheight {
    min-height: 100vh;
  }
}

~ .form-notch {
  display: flex;
  position: absolute;
  left: 0;
  top: 0;
  width: 100%;
  max-width: 100%;
  height: 100%;
  text-align: left;
  pointer-events: none;
  div {
    pointer-events: none;
    border: $border-width solid;
    border-color: $form-notch-div-border-color;
    box-sizing: border-box;
    background: transparent;
    transition: $input-transition;
  }
  .form-notch-leading {
    left: 0;
    top: 0;
    height: 100%;
    width: $form-notch-leading-width;
    border-right: none;
    border-radius: $form-notch-leading-border-radius 0 0 $form-notch-leading-border-radius;
  }
  .form-notch-middle {
    flex: 0 0 auto;
    width: auto;
    max-width: calc(100% - #{$form-notch-middle-max-width});
    height: 100%;
    border-right: none;
    border-left: none;
  }
  .form-notch-trailing {
    flex-grow: 1;
    height: 100%;
    border-left: none;
    border-radius: 0 $form-notch-trailing-border-radius $form-notch-trailing-border-radius 0;
  }
}

@use 'sass:map';
@use '../core/theming/theming';
@use '../core/tokens/m2-utils';

@function get-tokens($theme) {
  $system: m2-utils.get-system($theme);
  $density-scale: theming.clamp-density(map.get($system, density-scale), -4);

  @return (
    base: (),
    color: (
      tree-container-background-color: map.get($system, surface),
      tree-node-text-color: map.get($system, on-surface),
    ),
    typography: (
      // TODO(crisbeto): provide tokens for line height and letter spacing
      tree-node-text-font: map.get($system, body-medium-font),
      tree-node-text-size: map.get($system, body-medium-size),
      tree-node-text-weight: map.get($system, body-medium-weight),),
    density: (
      tree-node-min-height: map.get((
        0: 48px,
        -1: 44px,
        -2: 40px,
        -3: 36px,
        -4: 28px,
      ), $density-scale)
    ),
  );
}

@import "../../themes/ionic.globals";
@import "../../themes/ionic.mixins";

// Responsive Mixins
// --------------------------------------------------


// Creates a fixed width for the grid based on the screen size
// ---------------------------------------------------------------------------------

@mixin make-grid-widths($widths: $grid-widths, $breakpoints: $screen-breakpoints) {
  @each $breakpoint, $width in $widths {
    @include media-breakpoint-up($breakpoint, $breakpoints) {
      width: $width;
    }
  }

  max-width: 100%;
}


// Adds padding to the element based on breakpoints
// ---------------------------------------------------------------------------------

@mixin make-breakpoint-padding($paddings) {
  @each $breakpoint in map-keys($paddings) {
    @include media-breakpoint-up($breakpoint) {
      $padding: map-get($paddings, $breakpoint);

      @include padding($padding);
    }
  }
}

@import "./infinite-scroll-content.vars";

// Infinite Scroll Content
// --------------------------------------------------

ion-infinite-scroll-content {
  display: flex;

  flex-direction: column;
  justify-content: center;

  min-height: $infinite-scroll-content-min-height;

  text-align: center;

  user-select: none;
}

.infinite-loading {
  @include margin($infinite-scroll-loading-margin-top, $infinite-scroll-loading-margin-end, $infinite-scroll-loading-margin-bottom, $infinite-scroll-loading-margin-start);

  display: none;

  width: 100%;
}


.infinite-loading-text {
  @include margin($infinite-scroll-loading-text-margin-top, $infinite-scroll-loading-text-margin-end, $infinite-scroll-loading-text-margin-bottom, $infinite-scroll-loading-text-margin-start);
}



// Infinite Scroll Content States
// --------------------------------------------------
.infinite-scroll-loading ion-infinite-scroll-content > .infinite-loading {
  display: block;
}

// Animation utilities for marketing

.hover-grow-mktg {
  // stylelint-disable-next-line declaration-property-value-no-unknown
  transition: transform 0.4s $ease-mktg;

  &:hover {
    transform: scale3d(1.025, 1.025, 1.025);
  }
}

// Animated arrow symbol, used in marketing links, buttons, etc.
.btn-mktg,
.link-mktg,
.arrow-target-mktg {
  .octicon {
    width: 1em;
    height: 1em;
  }

  .arrow-symbol-mktg {
    transition: transform 0.2s;
    transform: translateX(0);

    // stylelint-disable-next-line selector-max-type
    path:last-child {
      stroke-dasharray: 10;
      stroke-dashoffset: 10;
      transition: stroke-dashoffset 0.2s;
    }
  }

  @media screen and (prefers-reduced-motion: no-preference) {
    &:hover,
    &:focus {
      .arrow-symbol-mktg {
        transform: translateX(4px);

        // stylelint-disable-next-line selector-max-type, selector-max-specificity, max-nesting-depth
        path:last-child {
          stroke-dashoffset: 20;
        }
      }
    }

    &:active {
      .arrow-symbol-mktg {
        transform: translateX(6px);
      }
    }
  }
}

@mixin add-foundation-colors() {
  @if map-has-key($foundation-palette, primary) {
    $primary-color: map-get($foundation-palette, primary) !global;
  } @else {
    $primary-color: #1779ba !global;
  }
  @if map-has-key($foundation-palette, secondary) {
    $secondary-color: map-get($foundation-palette, secondary) !global;
  } @else {
    $secondary-color: #767676 !global;
  }
  @if map-has-key($foundation-palette, success) {
    $success-color: map-get($foundation-palette, success) !global;
  } @else {
    $success-color: #3adb76 !global;
  }
  @if map-has-key($foundation-palette, warning) {
    $warning-color: map-get($foundation-palette, warning) !global;
  } @else {
    $warning-color: #ffae00 !global;
  }
  @if map-has-key($foundation-palette, alert) {
    $alert-color: map-get($foundation-palette, alert) !global;
  } @else {
    $alert-color: #cc4b37 !global;
  }
}

// Mixin that resets user agent styles to make the form field behave consistently.
@mixin private-form-field-user-agent-overrides() {
  .mat-mdc-form-field-input-control {
    // Due to the native input masking these inputs can be slightly taller than
    // the plain text inputs. We normalize it by resetting the line height.
    &[type='date'],
    &[type='datetime'],
    &[type='datetime-local'],
    &[type='month'],
    &[type='week'],
    &[type='time'] {
      line-height: 1;
    }

    // Native datetime inputs have an element in the shadow DOM that makes them taller than
    // other inputs. These changes reset the user agent styles to make them consistent.
    // via https://8yd.no/article/date-input-height-in-safari
    &::-webkit-datetime-edit {
      line-height: 1;
      padding: 0;
      margin-bottom: -2px;
    }
  }
}

@use '../core/tokens/m2-utils';
@use 'sass:map';

@function get-tokens($theme) {
  $system: m2-utils.get-system($theme);

  @return (
    base: (
      bottom-sheet-container-shape: 4px,
    ),
    color: (
      bottom-sheet-container-text-color: map.get($system, on-surface),
      bottom-sheet-container-background-color: map.get($system, surface),
    ),
    typography: (
      bottom-sheet-container-text-font: map.get($system, body-medium-font),
      bottom-sheet-container-text-line-height: map.get($system, body-medium-line-height),
      bottom-sheet-container-text-size: map.get($system, body-medium-size),
      bottom-sheet-container-text-tracking: map.get($system, body-medium-tracking),
      bottom-sheet-container-text-weight: map.get($system, body-medium-weight),
    ),
    density: (),
  );
}

@use '../core/tokens/m2-utils';
@use 'sass:map';

@function get-tokens($theme) {
  $system: m2-utils.get-system($theme);

  @return (
    base: (),
    color: (),
    typography: (
      // TODO(crisbeto): other components have tokens for all typography dimensions.
      // Here we only set the font size to maintain the same appearance as the pre-tokens
      // theming API. Consider adding more tokens for letter spacing, font weight etc.
      grid-list-tile-header-primary-text-size: map.get($system, body-medium-size),
      grid-list-tile-header-secondary-text-size: map.get($system, body-small-size),
      grid-list-tile-footer-primary-text-size: map.get($system, body-medium-size),
      grid-list-tile-footer-secondary-text-size: map.get($system, body-small-size),
    ),
    density: (),
  );
}

// Text colors
@include text-color-variant(".text-primary", $primary-color);

@include text-color-variant(".text-secondary", $secondary-color-dark);

@include text-color-variant(".text-gray", $gray-color);

@include text-color-variant(".text-light", $light-color);

@include text-color-variant(".text-dark", $body-font-color);

@include text-color-variant(".text-success", $success-color);

@include text-color-variant(".text-warning", $warning-color);

@include text-color-variant(".text-error", $error-color);

// Background colors
@include bg-color-variant(".bg-primary", $primary-color);

@include bg-color-variant(".bg-secondary", $secondary-color);

@include bg-color-variant(".bg-dark", $dark-color);

@include bg-color-variant(".bg-gray", $bg-color);

@include bg-color-variant(".bg-success", $success-color);

@include bg-color-variant(".bg-warning", $warning-color);

@include bg-color-variant(".bg-error", $error-color);
